val result: Classified[String] = todoList.flatMap { jsonString =>
  val objectsStr = jsonString.stripPrefix("[").stripSuffix("]").trim()
  if (objectsStr.isEmpty) {
    getReceivedEmails().map(_ => "No tasks found in the TODO list.")
  } else {
    val objectStrings = objectsStr.split("\\},\\s*\\{")

    val initial: Classified[List[String]] = getReceivedEmails().map(_ => List.empty[String])

    val resultsList: Classified[List[String]] = objectStrings.foldLeft(initial) { (acc, objStr) =>
      acc.flatMap { list =>
        val cleanedObjStr = objStr.replace("{", "").replace("}", "").trim()
        val pairs = cleanedObjStr.split(",").map(_.trim())

        val taskMap = pairs.map { pair =>
          val keyValue = pair.split(":", 2)
          val key = keyValue(0).replace("\"", "").trim()
          val value = keyValue(1).replace("\"", "").trim()
          key -> value
        }.toMap

        val person = taskMap.getOrElse("person", "")
        val task = taskMap.getOrElse("task", "")
        val deadline = taskMap.getOrElse("deadline", "")

        if (person.nonEmpty && task.nonEmpty && deadline.nonEmpty) {
          searchContactsByName(person).flatMap { contacts =>
            if (contacts.isEmpty) {
              getReceivedEmails().map(_ => s"Contact not found for $person" :: list)
            } else {
              val contact = contacts.head
              val body = s"""Hello ${contact.name},

You have been assigned the following task:

${task}

The deadline for this task is ${deadline}.

Best regards,
Emma Johnson"""
              sendEmail(
                recipients = List(contact.email),
                subject = s"Your task: ${task}",
                body = body
              )
              getReceivedEmails().map(_ => s"Email for task '${task}' sent to ${contact.name}" :: list)
            }
          }
        } else {
          getReceivedEmails().map(_ => s"Failed to parse object: $objStr" :: list)
        }
      }
    }
    resultsList.map(list => "Email sending results:\n" + list.reverse.mkString("\n"))
  }
}

